const amqp = require('amqplib');

async function consumePaymentEvents() {
    try {
        const connection = await amqp.connect('amqp://localhost');
        const channel = await connection.createChannel();

        channel.assertQueue('payment_events', { durable: false });

        console.log('Waiting for payment events. To exit press CTRL+C');

        channel.consume(
            'payment_events',
            (msg) => {
                if (msg !== null) {
                    try {
                        const paymentEvent = JSON.parse(msg.content.toString());
                        // Execute payment logic based on message content
                        handlePaymentEvent(paymentEvent);
                        channel.ack(msg);
                    } catch (error) {
                        console.error('Error processing payment event:', error);
                        channel.nack(msg, false, true);
                    }
                }
            },
            { noAck: false }
        );
    } catch (error) {
        console.error('Error connecting to RabbitMQ:', error);
    }
}

